using Bookgen.Lib.Domain.IO.Configuration;
using Bookgen.Lib.ImageService;
using Bookgen.Lib.Markdown;
using Bookgen.Lib.Markdown.RenderInterop;

using Moq;

namespace Bookgen.Tests.Lib;

[TestFixture]
internal sealed class UT_MarkdownConverter_Specials
{
    private Mock<IImgService> _imgServiceMock;
    private MarkdownRenderSettings _settings;
    private TestEnvironment _testEnvironment;
    private readonly IEqualityComparer<string?> comparer = new LineEndingIgnoreComparer();

    [SetUp]
    public void Setup()
    {
        _testEnvironment = new TestEnvironment();
        _imgServiceMock = new Mock<IImgService>(MockBehavior.Strict);

        _settings = new MarkdownRenderSettings(_imgServiceMock.Object)
        {
            CssClasses = new CssClasses(),
            DeleteFirstH1 = false,
            HostUrl = null,
            AutoEmbedSupportedLinks = true,
            RenderInterop = new RenderInterop(_testEnvironment, new ImageConfig()
            {
                SvgRecode = SvgRecodeOption.AsPng
            })
        };

    }

    [TearDown]
    public void Teardown()
    {
        _settings.Dispose();
        _testEnvironment.Dispose();
    }

    [Test]
    public void EnsureThat_TerminalRenderingWorks()
    {
        using var sut = new MarkdownConverter(_settings);

        string input = """
            ```terminal
            this is terminal output
            ```
            """;

        string expected = """
            <div style="margin-bottom: 1rem;" class="terminaloutput">
            <div style="background-color: #877EC2; color: #eee8d6; padding: 3px;">$</div>
            <pre style="text-align: left; font-size: 1.1em; line-height: 1.5; margin: 0px; padding: 8px; background-color: #282c34; color: #DCDFE4; font-family: Monaco, Menlo, Consolas, 'Courier New', monospace; word-break: break-all; word-wrap: break-word; overflow: auto;"><code style="tab-size: 4;">this is terminal output</code></pre>
            </div>
            """;

        string result = sut.RenderMarkdownToHtml(input);

        Assert.That(result, Is.EqualTo(expected).Using(comparer));
    }

    [Test]
    public void EnsureThat_NomnomlRender_PngWorks()
    {
        string input = """
            ```nomnoml
            [<frame>Foo|a;b;c]
            ```
            """;

        using var sut = new MarkdownConverter(_settings);

        string result = sut.RenderMarkdownToHtml(input);

        Assert.That(result, Does.StartWith("<img src=\"data:image/png;base64,"));
    }

    [Test]
    public void EnsureThat_NomnomlRender_SvgWorks()
    {
        string input = """
            ```nomnoml
            [<frame>Foo|a;b;c]
            ```
            """;

        using var settings = new MarkdownRenderSettings(_imgServiceMock.Object)
        {
            CssClasses = new CssClasses(),
            DeleteFirstH1 = false,
            HostUrl = null,
            AutoEmbedSupportedLinks = true,
            RenderInterop = new RenderInterop(_testEnvironment, new ImageConfig
            {
                SvgRecode = SvgRecodeOption.Passtrough
            })
        };

        using var sut = new MarkdownConverter(settings);

        string result = sut.RenderMarkdownToHtml(input);

        using (Assert.EnterMultipleScope())
        {
            Assert.That(result, Does.StartWith("<svg"));
            Assert.That(result, Does.EndWith("</svg>"));
        }
    }

    [Test]
    public void EnsrureThat_Youtube_LinkEmbedding_Works()
    {
        string input = """
            https://www.youtube.com/watch?v=D5ivt3hNAW8
            """;

        string expected = """
            <p><a href="https://www.youtube.com/watch?v=D5ivt3hNAW8" target="_blank">
            <img src="data:image/jpeg;base64,"><br>
            https://www.youtube.com/watch?v=D5ivt3hNAW8
            </a></p>
            
            """;

        using var sut = new MarkdownConverter(_settings);

        string result = sut.RenderMarkdownToHtml(input);

        Assert.That(result, Is.EqualTo(expected).Using(comparer));
    }


    [Test]
    public void EnsrureThat_Mixcloud_LinkEmbedding_Works()
    {
        string input = """
            https://www.mixcloud.com/dj-tnrr/journey-to-eternity-part-3/
            """;

        string expected = """
            <p><iframe width="100%" height="120" src="https://player-widget.mixcloud.com/widget/iframe/?hide_cover=1&feed=%2fdj-tnrr%2fjourney-to-eternity-part-3%2f" frameborder="0" allow="encrypted-media; fullscreen; autoplay; idle-detection; speaker-selection; web-share;" ></iframe></p>

            """;

        using var sut = new MarkdownConverter(_settings);

        string result = sut.RenderMarkdownToHtml(input);

        Assert.That(result, Is.EqualTo(expected).Using(comparer));
    }

}
